import { useEffect, useState } from "react"

const paymentPlans = [{
    planTitle: '24x',
    planDuration: '24',
    planTag: 'Bestseller',
    id: 'plan-1'
},
{
    planTitle: '12x',
    planDuration: '12 months',
    planTag: 'Most Popular',
    id: 'plan-2'
},
{
    planTitle: '6x',
    planDuration: '6 months',
    planTag: 'Balanced',
    id: 'plan-3'
},
{
    planTitle: '3x',
    planDuration: '3 months',
    planTag: 'Quick Pay',
    id: 'plan-4'
}
]

async function getData() {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            return resolve(paymentPlans)
        }, 500)
    })

}

function useData() {
    const [resp, setResp] = useState({
        data: null,
        loading: false,
        error: null
    })

    async function fetchData() {
        setResp((prev) => {
            return {
                ...prev,
                loading: true
            }
        })
        try {
            const result = await getData()
            setResp((prev) => {
                return {
                    ...prev,
                    data: result
                }
            })
        } catch (err) {
            setResp((prev) => {
                return {
                    ...prev,
                    error: 'Following error occured:' + err
                }
            })
        } finally {
            setResp((prev) => {
                return {
                    ...prev,
                    loading: false
                }
            })
        }
    }

    useEffect(() => {
        fetchData()
    }, [])

    return resp
}

export default useData
